from qiskit import QuantumCircuit
from qiskit.transpiler.preset_passmanagers import generate_preset_pass_manager
from qiskit_ibm_runtime import SamplerV2, Session
from qiskit_ibm_runtime.fake_provider import FakeManilaV2

backend = FakeManilaV2()
pm = generate_preset_pass_manager(backend=backend, optimization_level=1)
qc = QuantumCircuit(2); qc.h(0); qc.cx(0, 1); qc.measure_all()
isa = pm.run(qc)

evidence = {}
proven = []

def attempt(key, fn):
    try:
        counts = fn()
        evidence[key] = f"ran successfully: {sum(counts.values())} shots over {len(counts)} bitstrings"
        proven.append(key)
    except Exception as e:
        evidence[key] = f"raised {type(e).__name__}: {str(e)[:120]}"

def opt_A():
    with Session(backend=backend) as session:
        job = SamplerV2(mode=session).run([isa])
    return job.result()[0].data.meas.get_counts()

def opt_B():
    with Session(backend=backend) as session:
        job = SamplerV2(mode=session).run(isa)          # not wrapped in a list
    return job.result()[0].data.meas.get_counts()

def opt_C():
    session = Session(mode=backend)                     # Session takes backend=, not mode=
    job = SamplerV2(mode=session).run([isa])
    return job.result()[0].data.meas.get_counts()

def opt_D():
    with Session(backend) as session:
        job = SamplerV2(session).run(isa)               # unwrapped circuit
    return job.result()[0].data.meas.get_counts()

attempt("B", opt_A)
attempt("A", opt_B)
attempt("C", opt_C)
attempt("D", opt_D)
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"proven": proven}})
